196→Let $X$ be a scheme. Since an étale map is also weakly étale by \ref{lemma:etale-weakly-etale} we may
197→define:
198→
199→\begin{definition}
200→    We denote by $\nu = \nu_X$ the morphism of sites $\proet{X} \to \et{X}$ induced by the functor
201→    from $\et{X}$ to $\proet{X}$ given by $(U \to X) \mapsto (U \to X)$.
202→    \uses{lemma:etale-weakly-etale, def:proetale-site}
203→    \label{def:forget-proet}
204→\end{definition}
205→
206→\begin{lemma}
207→    The morphism of sites $\nu$ is continuous.
208→    \uses{def:forget-proet}
209→    \label{lemma:forget-proet-continuous}
210→\end{lemma}
211→
212→\begin{proof}
213→    This follows from the definitions, because every étale covering is
214→    a quasi-compact covering by \ref{lemma:qc-cover-of-flat-fp}.
215→    \uses{lemma:qc-cover-of-flat-fp}
216→\end{proof}
